import React from 'react';
import axios from 'axios';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

function UserProfile({ user, currentUser, onClose, onStartChat }) {
  const getAvatarUrl = (avatarPath) => {
    if (!avatarPath) return null;
    if (avatarPath.startsWith('http')) return avatarPath;
    return `${API_URL}${avatarPath}`;
  };

  const formatDate = (dateString) => {
    if (!dateString) return 'неизвестно';
    const date = new Date(dateString);
    return date.toLocaleDateString('ru-RU', {
      day: 'numeric',
      month: 'long',
      year: 'numeric'
    });
  };

  return (
    <div style={{
      position: 'fixed',
      top: 0,
      left: 0,
      right: 0,
      bottom: 0,
      background: 'rgba(0, 0, 0, 0.8)',
      backdropFilter: 'blur(10px)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      zIndex: 1000
    }}>
      <div style={{
        width: '90%',
        maxWidth: '400px',
        background: 'var(--bg-secondary)',
        borderRadius: '20px',
        overflow: 'hidden',
        boxShadow: '0 20px 60px rgba(0,0,0,0.5)'
      }}>
        {/* Шапка */}
        <div style={{
          padding: '20px',
          background: 'var(--bg-tertiary)',
          borderBottom: '1px solid var(--border-color)',
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center'
        }}>
          <h2 style={{ margin: 0, color: 'var(--text-primary)' }}>Профиль</h2>
          <button
            onClick={onClose}
            style={{
              background: 'none',
              border: 'none',
              color: 'var(--text-secondary)',
              fontSize: '24px',
              cursor: 'pointer'
            }}
          >
            ✕
          </button>
        </div>

        {/* Контент */}
        <div style={{ padding: '30px 20px', textAlign: 'center' }}>
          {/* Аватарка */}
          <div style={{
            width: '120px',
            height: '120px',
            borderRadius: '50%',
            background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
            margin: '0 auto 20px',
            overflow: 'hidden',
            border: '3px solid var(--accent-color)'
          }}>
            {user.avatar ? (
              <img 
                src={getAvatarUrl(user.avatar)} 
                alt={user.displayName}
                style={{ width: '100%', height: '100%', objectFit: 'cover' }}
              />
            ) : (
              <div style={{
                width: '100%',
                height: '100%',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                fontSize: '48px',
                color: 'white'
              }}>
                {user.displayName[0].toUpperCase()}
              </div>
            )}
          </div>

          {/* Имя и username */}
          <h2 style={{ color: 'var(--text-primary)', margin: '0 0 5px' }}>
            {user.displayName}
          </h2>
          <p style={{ color: 'var(--text-secondary)', margin: '0 0 20px' }}>
            @{user.username}
          </p>

          {/* Статус онлайн */}
          <div style={{
            display: 'inline-block',
            padding: '5px 15px',
            borderRadius: '20px',
            background: user.online ? 'rgba(76, 175, 80, 0.2)' : 'rgba(158, 158, 158, 0.2)',
            color: user.online ? '#4caf50' : '#9e9e9e',
            marginBottom: '20px'
          }}>
            {user.online ? '🟢 В сети' : '⚫ Не в сети'}
          </div>

          {/* Информация */}
          <div style={{
            background: 'var(--bg-tertiary)',
            borderRadius: '10px',
            padding: '15px',
            marginBottom: '20px',
            textAlign: 'left'
          }}>
            {user.bio && (
              <div style={{ marginBottom: '15px' }}>
                <div style={{ color: 'var(--text-secondary)', fontSize: '12px', marginBottom: '5px' }}>
                  О себе
                </div>
                <div style={{ color: 'var(--text-primary)' }}>
                  {user.bio}
                </div>
              </div>
            )}
            
            <div style={{ marginBottom: '10px' }}>
              <div style={{ color: 'var(--text-secondary)', fontSize: '12px', marginBottom: '5px' }}>
                Email
              </div>
              <div style={{ color: 'var(--text-primary)' }}>
                {user.email}
              </div>
            </div>

            {user.phone && (
              <div style={{ marginBottom: '10px' }}>
                <div style={{ color: 'var(--text-secondary)', fontSize: '12px', marginBottom: '5px' }}>
                  Телефон
                </div>
                <div style={{ color: 'var(--text-primary)' }}>
                  {user.phone}
                </div>
              </div>
            )}

            <div>
              <div style={{ color: 'var(--text-secondary)', fontSize: '12px', marginBottom: '5px' }}>
                На сайте с
              </div>
              <div style={{ color: 'var(--text-primary)' }}>
                {formatDate(user.createdAt)}
              </div>
            </div>
          </div>

          {/* Кнопки действий */}
          <div style={{ display: 'flex', gap: '10px' }}>
            {currentUser.id !== user.id && (
              <button
                onClick={() => {
                  onStartChat(user);
                  onClose();
                }}
                style={{
                  flex: 1,
                  padding: '12px',
                  background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
                  border: 'none',
                  borderRadius: '10px',
                  color: 'white',
                  fontSize: '16px',
                  cursor: 'pointer',
                  transition: 'all 0.3s'
                }}
                onMouseEnter={(e) => {
                  e.target.style.transform = 'translateY(-2px)';
                  e.target.style.boxShadow = '0 10px 20px rgba(102, 126, 234, 0.4)';
                }}
                onMouseLeave={(e) => {
                  e.target.style.transform = 'translateY(0)';
                  e.target.style.boxShadow = 'none';
                }}
              >
                ✉️ Написать
              </button>
            )}
            <button
              onClick={onClose}
              style={{
                flex: currentUser.id !== user.id ? '0 0 auto' : '1',
                padding: '12px 24px',
                background: 'transparent',
                border: '1px solid var(--border-color)',
                borderRadius: '10px',
                color: 'var(--text-primary)',
                fontSize: '16px',
                cursor: 'pointer',
                transition: 'all 0.3s'
              }}
              onMouseEnter={(e) => {
                e.target.style.background = 'var(--bg-hover)';
              }}
              onMouseLeave={(e) => {
                e.target.style.background = 'transparent';
              }}
            >
              Закрыть
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

export default UserProfile;
